{"code":"async (page) => {
  const client = await page.context().newCDPSession(page);
  await client.send('Security.setIgnoreCertificateErrors', { ignore: true });
  await page.goto('https://secman.covestro.net/admin/translation-config', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(1000);

  const inputInfo = await page.locator('#modelName').evaluate((input) => ({
    tagName: input.tagName,
    type: input.getAttribute('type'),
    list: input.getAttribute('list'),
    value: (input as HTMLInputElement).value,
  }));
  const options = await page.locator('#openrouter-models option').evaluateAll((nodes) =>
    nodes.map((node) => ({ value: node.getAttribute('value'), label: node.textContent }))
  );
  await page.locator('#modelName').fill('custom/provider-model-name');
  const customValue = await page.locator('#modelName').inputValue();

  return {
    url: page.url(),
    title: await page.title(),
    inputInfo,
    customValue,
    hasOpus46: options.some((option) => option.value === 'anthropic/claude-opus-4.6'),
    hasSonnetLatest: options.some((option) => option.value === '~anthropic/claude-sonnet-latest'),
    hasHaikuLatest: options.some((option) => option.value === '~anthropic/claude-haiku-latest'),
    hasDeepSeekV4Pro: options.some((option) => option.value === 'deepseek/deepseek-v4-pro'),
    hasDeepSeekV4Flash: options.some((option) => option.value === 'deepseek/deepseek-v4-flash'),
    optionCount: options.length,
  };
}"}

