async (page) => {
  const client = await page.context().newCDPSession(page);
  await client.send('Security.setIgnoreCertificateErrors', { ignore: true });
  await page.goto('https://secman.covestro.net/admin/translation-config', { waitUntil: 'domcontentloaded' });
  await page.waitForTimeout(1000);
  await page.getByRole('button', { name: 'Add New Configuration' }).click();
  await page.waitForSelector('#modelOption', { timeout: 5000 });

  const initial = {
    modelOptionTag: await page.locator('#modelOption').evaluate((el) => el.tagName),
    customInputTag: await page.locator('#modelName').evaluate((el) => el.tagName),
    customDisabled: await page.locator('#modelName').isDisabled(),
    selectedValue: await page.locator('#modelOption').inputValue(),
  };

  await page.locator('#modelOption').selectOption('__custom__');
  await page.locator('#modelName').fill('custom/provider-model-name');

  return {
    initial,
    customDisabledAfterSelect: await page.locator('#modelName').isDisabled(),
    customValue: await page.locator('#modelName').inputValue(),
    hasOpus46: await page.locator('#modelOption option[value="anthropic/claude-opus-4.6"]').count(),
    hasDeepSeekV4Pro: await page.locator('#modelOption option[value="deepseek/deepseek-v4-pro"]').count(),
    hasSonnetLatest: await page.locator('#modelOption option[value="~anthropic/claude-sonnet-latest"]').count(),
    hasHaikuLatest: await page.locator('#modelOption option[value="~anthropic/claude-haiku-latest"]').count(),
  };
}

